import scala.xml.{Elem, Node, XML}
import scala.util.{Try, Success, Failure}

final case class Setting(key: String, value: String)
final case class ParsedConfig(settings: Seq[Setting])

sealed trait ConfigParseError {
  def message: String
}
final case class InvalidXml(message: String) extends ConfigParseError
final case class MissingSetting(message: String) extends ConfigParseError

trait ConfigParserService {
  def parse(xmlInput: String): Either[ConfigParseError, ParsedConfig]
  def extractSetting(xmlInput: String, key: String): Either[ConfigParseError, String]
}

final class XmlConfigParserService extends ConfigParserService {

  override def parse(xmlInput: String): Either[ConfigParseError, ParsedConfig] = {
    loadXml(xmlInput).map { xml =>
      ParsedConfig(extractSettings(xml))
    }
  }

  override def extractSetting(xmlInput: String, key: String): Either[ConfigParseError, String] = {
    parse(xmlInput).flatMap { config =>
      config.settings.find(_.key == key) match {
        case Some(setting) => Right(setting.value)
        case None          => Left(MissingSetting(s"Setting not found: $key"))
      }
    }
  }

  private def loadXml(xmlInput: String): Either[ConfigParseError, Elem] = {
    Try(XML.loadString(xmlInput)) match {
      case Success(xml) => Right(xml)
      case Failure(ex)  => Left(InvalidXml(s"Failed to parse XML: ${ex.getMessage}"))
    }
  }

  private def extractSettings(xml: Elem): Seq[Setting] = {
    val directSettings =
      (xml \\ "setting").flatMap { node =>
        extractSettingNode(node)
      }

    val propertySettings =
      (xml \\ "property").flatMap { node =>
        extractPropertyNode(node)
      }

    (directSettings ++ propertySettings)
      .groupBy(_.key)
      .view
      .mapValues(_.last)
      .values
      .toSeq
      .sortBy(_.key)
  }

  private def extractSettingNode(node: Node): Option[Setting] = {
    val key =
      node.attribute("key").map(_.text.trim).filter(_.nonEmpty)
        .orElse(node.attribute("name").map(_.text.trim).filter(_.nonEmpty))

    val value =
      node.attribute("value").map(_.text.trim)
        .orElse {
          val textValue = node.text.trim
          if (textValue.nonEmpty) Some(textValue) else None
        }

    for {
      k <- key
      v <- value
    } yield Setting(k, v)
  }

  private def extractPropertyNode(node: Node): Option[Setting] = {
    val key = node.attribute("name").map(_.text.trim).filter(_.nonEmpty)
    val value =
      node.attribute("value").map(_.text.trim)
        .orElse {
          val textValue = node.text.trim
          if (textValue.nonEmpty) Some(textValue) else None
        }

    for {
      k <- key
      v <- value
    } yield Setting(k, v)
  }
}

object ConfigParserApiExample {
  private val service: ConfigParserService = new XmlConfigParserService

  def handleParseRequest(xmlPayload: String): Either[String, Map[String, String]] = {
    service.parse(xmlPayload).map { parsed =>
      parsed.settings.map(s => s.key -> s.value).toMap
    }.left.map(_.message)
  }

  def handleExtractRequest(xmlPayload: String, key: String): Either[String, String] = {
    service.extractSetting(xmlPayload, key).left.map(_.message)
